-- Create "user_announcement_reads" table
CREATE TABLE "user_announcement_reads" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "user_id" bigint NOT NULL,
  "announcement_id" bigint NOT NULL,
  "read_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "userannouncementread_announcement_id" to table: "user_announcement_reads"
CREATE INDEX "userannouncementread_announcement_id" ON "user_announcement_reads" ("announcement_id");
-- Create index "userannouncementread_user_id_announcement_id" to table: "user_announcement_reads"
CREATE UNIQUE INDEX "userannouncementread_user_id_announcement_id" ON "user_announcement_reads" ("user_id", "announcement_id");
-- Create index "userannouncementread_user_id_read_at" to table: "user_announcement_reads"
CREATE INDEX "userannouncementread_user_id_read_at" ON "user_announcement_reads" ("user_id", "read_at");
